#include <stdio.h>

int main() {
    int B[3], S[3], M[3];
    scanf("%d %d %d", &B[0], &B[1], &B[2]);
    scanf("%d %d %d", &S[0], &S[1], &S[2]);
    scanf("%d %d %d", &M[0], &M[1], &M[2]);

    for (int i = 0; i < 3; i++) {
        int bulbIndex = M[i] - 1;
        if (S[i] == 1)
            B[bulbIndex] = 1 - B[bulbIndex];
    }

    printf("%d %d %d", B[0], B[1], B[2]);
    return 0;
}
